import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is BMR (Basal Metabolic Rate)?", a: "BMR is the number of calories your body burns at complete rest - just to maintain basic physiological functions like breathing, circulation, and cell production. It represents 60-75% of total daily energy expenditure for most people." },
  { q: "Which BMR formula is most accurate?", a: "The Mifflin-St Jeor equation (used here) is considered the most accurate for most people, with an average error of - The Harris-Benedict equation is older and slightly less accurate. For best results, use body composition data when available." },
  { q: "How does muscle mass affect BMR?", a: "Muscle tissue burns more calories at rest than fat tissue. People with higher muscle mass have higher BMRs. This is why strength training increases your resting calorie burn over time, even on non-workout days." },
  { q: "How can I increase my BMR?", a: "Build muscle through strength training (most effective), stay adequately hydrated (dehydration reduces BMR), ensure adequate sleep (poor sleep reduces BMR by 5-20%), avoid extreme calorie restriction (causes adaptive thermogenesis), and eat sufficient protein." },
  { q: "What is the difference between BMR and TDEE?", a: "BMR is calories burned at complete rest. TDEE (Total Daily Energy Expenditure) is BMR multiplied by an activity factor - it accounts for your actual movement throughout the day. TDEE is what you should use for calorie counting." },
  { q: "How many calories should I eat to lose weight?", a: "Eat 500-750 calories below your TDEE to lose approximately 1-1.5 lbs per week. Never eat below your BMR for extended periods - it causes muscle loss and metabolic slowdown. A deficit of 500 cal/day leads to ~1 lb of fat loss per week." },
  { q: "Does BMR decrease with age?", a: "Yes. BMR typically declines by 1-2% per decade after age 20, partly due to muscle loss (sarcopenia). Staying active and maintaining muscle mass through resistance training significantly slows this decline." },
];

export default function BMRCalculator() {
  const [gender, setGender] = useState<"male" | "female">("male");
  const [age, setAge] = useState(30);
  const [heightCm, setHeightCm] = useState(175);
  const [weightKg, setWeightKg] = useState(75);

  const bmrMifflin = gender === "male"
    ? 10 * weightKg + 6.25 * heightCm - 5 * age + 5
    : 10 * weightKg + 6.25 * heightCm - 5 * age - 161;
  const bmrHarris = gender === "male"
    ? 88.362 + 13.397 * weightKg + 4.799 * heightCm - 5.677 * age
    : 447.593 + 9.247 * weightKg + 3.098 * heightCm - 4.330 * age;

  const activityLevels = [
    { label: "Sedentary", factor: 1.2, desc: "Little or no exercise" },
    { label: "Light", factor: 1.375, desc: "Exercise 1-3 days/week" },
    { label: "Moderate", factor: 1.55, desc: "Exercise 3-5 days/week" },
    { label: "Active", factor: 1.725, desc: "Hard exercise 6-7 days/week" },
    { label: "Very Active", factor: 1.9, desc: "Very hard exercise, physical job" },
  ];

  return (
    <>
      <SEOHead
        title="Free BMR Calculator Online - Calculate Basal Metabolic Rate Instantly | CalcHive"
        description="Free online BMR calculator. Calculate your Basal Metabolic Rate and find out how many calories your body burns at complete rest. 100% free, no account needed, works for everyone."
        canonical="/bmr-calculator"
        keywords="free BMR calculator, basal metabolic rate calculator free online, calculate BMR free, free resting calorie calculator, BMR calculator no signup"
        category="Health Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free BMR Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free BMR calculator to calculate BMR free and estimate how many calories your body burns at rest. This basal metabolic rate calculator free online also works as a free resting calorie calculator and BMR calculator no signup tool.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="flex gap-2 mb-6">
            {(["male", "female"] as const).map(g => (
              <button key={g} onClick={() => setGender(g)} className={`px-4 py-1.5 rounded-full text-sm font-semibold border capitalize transition-all ${gender === g ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>{g}</button>
            ))}
          </div>
          <div className="space-y-6 mb-8">
            <SliderInput id="age-bmr" label="Age" value={age} min={1} max={120} step={0.1} onChange={setAge} format={v => `${v} years`} testId="input-age" />
            <SliderInput id="height-bmr" label="Height" value={heightCm} min={91.44} max={243.84} step={0.1} onChange={setHeightCm} format={v => `${v} cm`} testId="input-height" />
            <SliderInput id="weight-bmr" label="Weight" value={weightKg} min={30} max={635} step={0.1} onChange={setWeightKg} format={v => `${v} kg`} testId="input-weight" />
          </div>
          <motion.div key={`${gender}-${age}-${heightCm}-${weightKg}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">BMR (Mifflin-St Jeor)</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-bmr">{Math.round(bmrMifflin).toLocaleString()}</p>
              <p className="text-white/70 text-sm mt-1">calories/day at complete rest</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[{ label: "Harris-Benedict BMR", value: `${Math.round(bmrHarris).toLocaleString()} cal` }, { label: "Calories/Hour at Rest", value: `${(bmrMifflin / 24).toFixed(0)} cal` }, { label: "Calories/Week at Rest", value: `${Math.round(bmrMifflin * 7).toLocaleString()} cal` }].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-base font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <MedicalDisclaimer /><ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your BMR for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Two equations dominate BMR calculation. The Mifflin-St Jeor equation (1990) is considered the gold standard for non-obese adults. The Harris-Benedict equation (revised 1984) is slightly older but still widely referenced.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-3">
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Mifflin-St Jeor (recommended)</p>
              <p>Male: BMR = (10  x  kg) + (6.25  x  cm) - (5  x  age) + 5</p>
              <p>Female: BMR = (10  x  kg) + (6.25  x  cm) - (5  x  age) - 161</p>
            </div>
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Harris-Benedict (revised)</p>
              <p>Male: BMR = 88.36 + (13.40  x  kg) + (4.80  x  cm) - (5.68  x  age)</p>
              <p>Female: BMR = 447.59 + (9.25  x  kg) + (3.10  x  cm) - (4.33  x  age)</p>
            </div>
          </div>

          <h2 className="text-2xl font-bold text-foreground">What is Basal Metabolic Rate and Why it Matters</h2>
          <p className="text-muted-foreground leading-relaxed">Multiply your BMR by the activity factor that best matches your lifestyle to get your TDEE - the total calories you need to maintain your current weight.</p>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Activity Level", "Multiplier", "Description", `TDEE (BMR = ${Math.round(bmrMifflin)} cal)`].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {activityLevels.map(({ label, factor, desc }) => (
                  <tr key={label} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{label}</td>
                    <td className="py-2.5 px-4 text-muted-foreground"> x {factor}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{desc}</td>
                    <td className="py-2.5 px-4 font-semibold text-teal-600 dark:text-teal-400">{Math.round(bmrMifflin * factor).toLocaleString()} cal</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Metabolism Calculator for Everyone</h2>
          <ul className="space-y-2 text-muted-foreground list-disc list-inside">
            <li><strong className="text-foreground">To lose weight:</strong> Eat 500-750 calories below your TDEE. This creates a deficit that leads to 1-1.5 lbs of fat loss per week without significant muscle loss.</li>
            <li><strong className="text-foreground">To maintain weight:</strong> Eat at your TDEE. Track your weight for 2-3 weeks and adjust by - calories as needed based on actual weight trend.</li>
            <li><strong className="text-foreground">To gain muscle:</strong> Eat 200-500 calories above your TDEE (a "lean bulk"). Higher surpluses lead to more fat gain alongside muscle.</li>
            <li><strong className="text-foreground">Never eat below BMR</strong> for extended periods - it causes muscle catabolism, hormonal disruption, and metabolic adaptation.</li>
          </ul>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/bmr-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


